+        b"%[a-zA-Z0-9]".to_vec(),
+        b"%[^\\n]".to_vec(),
+        // Edge: ] as first character
+        b"%[]a]".to_vec(),
+        b"%[^]a]".to_vec(),
+    ];
+
+    for fmt in &scanset_formats {
+        let directives = parse_scanf_format(fmt);
+        if !directives.is_empty() {
+            let result = scan_input(data, &directives);
+            let _ = result.count;
+        }
+    }
